# Apply Phase 2 schema script Write-Host "Applying Phase 2 schema to TimescaleDB..." try {     # Set password environment variable     $env:PGPASSWORD = "password"      # Read the SQL file and pipe to psql     Get-Content "init_phase2.sql" -Raw | docker exec -i trading_timescaledb psql -U trading -d trading_bot      # Check if the command succeeded     if ($LASTEXITCODE -eq 0) {         Write-Host "✅ SUCCESS: Phase 2 schema applied successfully!"     } else {         Write-Host "❌ FAILED: Error applying schema. Exit code: $LASTEXITCODE"         exit 1     } } catch {     Write-Host "❌ ERROR: $_"     exit 1 } finally {     # Clean up environment variable     Remove-Item env:PGPASSWORD }
